def token_case(s):
    exceptions = {'URL', 'ID'}
    tokens = s.split('_')
    camel_case = []

    for token in tokens:
        if token not in exceptions and token:  # edge case: empty string
            if token == 'URL' or token == 'ID':
                camel_case.append(token)
            elif token[0].isupper():
                camel_case.append(token)
            else:
                camel_case.append(token[0].lower() + token[1:])
        else:
            camel_case.append(token)

    return ''.join(camel_case)
